<template>
  <div class="merchant-store">
    <SpForm
      ref="form"
      v-model="form"
      show-message
      label-width="100px"
      :form-list="formList"
      :submit="false"
    />

    <div class="footer-container">
      <el-button @click.native="handleCancel"> 取消 </el-button>
      <el-button
        v-if="!VERSION_STANDARD || (!IS_DISTRIBUTOR && VERSION_STANDARD)"
        type="primary"
        :loading="submitLoading"
        @click="onFormSubmit"
      >
        {{ submitLoading ? '提交中' : '儲存' }}
      </el-button>
    </div>
  </div>
</template>

<script>
import { isObject, isArray, isEmpty, getRegionNameById } from '@/utils'
import Pages from '@/utils/pages'
import district from '@/common/district.json'
import DaoDianZiti from './components/DaoDianZiti'
import RefundGoodsAddress from './components/RefundGoodsAddress'
import RefundGoodsStore from './components/RefundGoodsStore'
export default {
  data() {
    let distributionTypeOptions = [
      {
        title: '自營',
        value: 0
      }
    ]
    if (!this.VERSION_STANDARD) {
      distributionTypeOptions.push({
        title: '加盟',
        value: 1
      })
    }
    return {
      form: {
        distribution_type: 0, // 店鋪類型： 0=自營；1=加盟
        merchant_id: '',
        shop_code: '',
        name: '',
        contact: '',
        mobile: '',
        contract_phone: '',
        startTime: '',
        endTime: '',
        is_delivery: false,
        is_audit_goods: false,
        auto_sync_goods: false,
        is_require_subdistrict: false,
        is_require_building: false,
        logo: '',
        banner: '',
        lng: '121.54314',
        lat: '25.04742',
        regions_id: ['710000', '710100', '710101'],
        address: '',
        is_dada: false,
        business: '',
        is_ziti: false,
        offline_aftersales: false,
        offline_aftersales_address: {
          name: '',
          regions_id: '',
          address: '',
          area_code: '',
          mobile: '',
          startTime: '',
          endTime: ''
        },
        offline_aftersales_other: false,
        introduce: ''
      },
      formList: [
        {
          label: '店鋪類型',
          type: 'group',
          isShow: ({ key }, value) => this.IS_ADMIN && this.distributor_self == 0
        },
        {
          label: '店鋪類型',
          key: 'distribution_type',
          type: 'select',
          clearable: false,
          options: distributionTypeOptions,
          isShow: ({ key }, value) => this.IS_ADMIN && this.distributor_self == 0
        },
        {
          label: '所屬商戶',
          key: 'merchant_id',
          type: 'select',
          component: ({ key }, value) => {
            return (
              <el-select
                v-model={value[key]}
                v-scroll={() => this.pageQuery.nextPage()}
                class={[
                  {
                    'is-error': !value[key]
                  }
                ]}
                clearable
                on-clear={() => this.onRemoteGetMerchant()}
                on-focus={() => this.onRemoteGetMerchant()}
                filterable
                loading={this.remoteLoading}
                remote
                remote-method={(e) => this.onRemoteGetMerchant(e)}
                placeholder='輸入商戶名稱搜尋'
              >
                {this.merchantList.map((item, index) => (
                  <el-option
                    key={`option-item__${index}`}
                    label={item.merchant_name}
                    value={item.id}
                  />
                ))}
              </el-select>
            )
          },
          isShow: ({ key }, value) => {
            return value.distribution_type == 1 && this.IS_ADMIN && this.distributor_self == 0
          },
          validator: (rule, value, callback) => {
            if (this.form.distribution_type == 1 && !value) {
              callback(new Error('請選擇商戶'))
            } else {
              callback()
            }
          }
        },
        {
          label: '基礎訊息',
          type: 'group'
        },
        {
          label: '店鋪號',
          key: 'shop_code',
          type: 'input',
          display: 'inline',
          placeholder: '請輸入店鋪號(字母、數字)',
          required: true,
          validator: (rule, value, callback) => {
            if (!value) {
              callback(new Error('店鋪號不能為空'))
            } else if (!/^[A-Za-z0-9\-]+$/.test(value)) {
              callback(new Error('請輸入字母、數字'))
            } else {
              callback()
            }
          }
        },
        {
          label: '店鋪名稱',
          key: 'name',
          type: 'input',
          display: 'inline',
          placeholder: '請輸入店鋪名稱',
          required: true,
          message: '店鋪名稱不能為空'
        },
        {
          label: '聯絡人姓名',
          key: 'contact',
          type: 'input',
          display: 'inline',
          disabled: () => this.datapass_block == 1,
          placeholder: '請輸入聯絡人姓名',
          required: true,
          message: '聯絡人不能為空'
        },
        {
          label: '聯絡方式',
          key: 'mobile',
          type: 'input',
          display: 'inline',
          disabled: () => this.datapass_block == 1,
          placeholder: '請輸入聯絡人手機號碼',
          required: true,
          message: '聯絡方式不能為空'
        },
        {
          label: '市內電話',
          key: 'contract_phone',
          type: 'input',
          display: 'inline',
          placeholder: '請輸入市內電話'
        },
        {
          label: '經營時間',
          // key: 'contract_phone',
          display: 'inline',
          component: ({ key }, value) => {
            return (
              <div>
                <el-time-select
                  v-model={value['startTime']}
                  class='start-time'
                  placeholder='起始時間'
                  picker-options={{
                    start: '00:00',
                    step: '00:30',
                    end: '23:59'
                  }}
                />
                <span class='separator'>-</span>
                <el-time-select
                  v-model={value['endTime']}
                  class='end-time'
                  placeholder='結束時間'
                  picker-options={{
                    start: '00:00',
                    step: '00:30',
                    end: '23:59',
                    minTime: value.startTime
                  }}
                />
              </div>
            )
          }
        },
        {
          label: '是否快遞',
          key: 'is_delivery',
          type: 'switch',
          display: 'inline'
        },
        {
          label: '審核商品',
          key: 'is_audit_goods',
          type: 'switch',
          display: 'inline',
          width: '360px',
          tip: '開啟後，店鋪新增的自有商品，需要平台審核通過後才可以上架',
          isShow: ({ key }, value) => !this.VERSION_STANDARD && value.distribution_type == 0
        },
        {
          label: '同步商品',
          key: 'auto_sync_goods',
          type: 'switch',
          display: 'inline',
          tip: '自動同步商品至店鋪',
          isShow: ({ key }, value) =>
            this.VERSION_STANDARD && !this.IS_DISTRIBUTOR && this.distributor_self == 0
        },
        {
          label: '街道巷弄',
          key: 'is_require_subdistrict',
          type: 'switch',
          display: 'inline',
          tip: '下單是否需要選擇街道巷弄',
          isShow: ({ key }, value) => this.distributor_self == 0
        },
        {
          label: '樓號室',
          key: 'is_require_building',
          type: 'switch',
          display: 'inline',
          tip: '下單是否需要填寫樓號室',
          isShow: ({ key }, value) => this.distributor_self == 0
        },
        {
          label: '店鋪圖片',
          type: 'group',
          tip: '（只能上傳jpg/png文件，且不超過2M）'
        },
        {
          label: '店鋪Logo',
          key: 'logo',
          display: 'inline',
          component: ({ key }, value) => {
            return <SpImagePicker v-model={value[key]} />
          }
        },
        {
          label: '店鋪背景',
          key: 'banner',
          display: 'inline',
          component: ({ key }, value) => {
            return <SpImagePicker v-model={value[key]} />
          }
        },
        {
          label: '店鋪位置',
          type: 'group',
          tip: '（店鋪定位後儲存店鋪經緯度，才可以開啟自取，否則店鋪不支持自取功能）'
        },
        {
          label: '店鋪經緯度',
          component: ({ key }, value) => {
            return (
              <div class='lng-lat-block'>
                <el-input v-model={value.lng} readonly placeholder='經度' />
                <span class='separator'>-</span>
                <el-input v-model={value.lat} readonly placeholder='緯度' />
              </div>
            )
          }
        },
        {
          label: '地理位置',
          key: 'address',
          width: '1000px',
          component: ({ key }, value) => {
            return (
              <div class='address-block'>
                <el-cascader v-model={value['regions_id']} class='regions' options={district} />
                <el-input
                  v-model={value['address']}
                  class={[
                    'address',
                    {
                      'is-error': !value['address']
                    }
                  ]}
                  placeholder='請輸入詳細地址（去除省市縣）'
                />
                <el-button type='primary' on-click={this.findPlaceFromQuery}>
                  搜尋定位
                </el-button>

                <div v-show={this.qqmap_infowin_show} class='qqmap-infowin' id='qqmap_infowin'>
                  <div class='address-name'>{this.poi_info?.name}</div>
                  <div class='address-detail'>{this.poi_info?.address}</div>
                  <el-button type='primary' size='mini' on-click={this.importPosition}>
                    匯入位置訊息
                  </el-button>
                </div>
              </div>
            )
          },
          validator: (rule, value, callback) => {
            if (!this.form.address) {
              callback(new Error('詳細地址不能為空'))
            } else {
              callback()
            }
          }
        },
        {
          label: '',
          // component: ({ key }, value) => <div id='qqmap_container' />
          component: ({ key }, value) => <div id='googlemap_container' />
        },
        {
          label: '同城配',
          type: 'group',
          tip: '（需先選擇店鋪地理位置，系統根據店鋪位置判斷該地區是否支持同城配）',
          isShow: this.dadaEnable
        },
        {
          label: '達達同城配',
          key: 'is_dada',
          type: 'switch',
          width: 'auto',
          tip: '開啟後有店鋪訂單時需要改店鋪人員手動接單，接單後系統會自動在達達平台下單',
          isShow: this.dadaEnable
        },
        {
          label: '業務類型',
          key: 'business',
          type: 'select',
          options: [],
          isShow: ({ key }, value) => value.is_dada && this.dadaEnable,
          validator: (rule, value, callback) => {
            console.log('value:', value)
            if (this.form.is_dada) {
              if (!value) {
                callback(new Error('達達業務類型必填'))
              } else {
                callback()
              }
            } else {
              callback()
            }
          }
        },
        {
          label: '到店自取',
          type: 'group'
        },
        {
          label: '到店自取',
          key: 'is_ziti',
          type: 'switch',
          width: 'auto',
          tip: '啟用到店自取功能後，買家下單時可選擇下方地址自取，下單後你需要盡快將商品配送至指定自取點；下方自取地址共享該店鋪庫存。'
        },
        {
          label: '',
          width: '1000px',
          component: ({ key }, value) => <DaoDianZiti ref='daoDianZiti' />,
          isShow: ({ key }, value) => value.is_ziti
        },
        {
          label: '到店退貨',
          type: 'group'
        },
        {
          label: '本店訂單',
          key: 'offline_aftersales',
          type: 'switch',
          width: 'auto',
          tip: '啟用後本店訂單買家發起退貨退款申請時可選擇到店退貨，關閉時本店訂單僅可使用快遞退貨；商家發起的售後訂單不受此規則限制。'
        },
        {
          label: '本店退貨點',
          width: 'auto',
          component: ({ key }, value) => (
            <RefundGoodsAddress v-model={value['offline_aftersales_address']} />
          )
        },
        {
          label: '可退貨店鋪',
          width: '1000px',
          component: ({ key }, value) => (
            <RefundGoodsStore
              v-model={value['offline_aftersales_address']}
              ref='refundGoodsStore'
            />
          )
        },
        {
          label: '其他店鋪訂單',
          key: 'offline_aftersales_other',
          type: 'switch',
          width: 'auto',
          tip: '啟用後其他店鋪在設置可退貨店鋪時可選擇本店（即本店可接收其他店鋪訂單到店退貨）；商家發起的售後訂單不受此規則限制。'
        },
        {
          label: '店鋪介紹',
          type: 'group'
        },
        {
          label: '店鋪介紹',
          key: 'introduce',
          type: 'textarea',
          placeholder: '',
          width: '1000px'
        }
      ],
      merchantList: [],
      remoteLoading: false,
      regions: district,
      submitLoading: false,
      searchService: null,
      googleMap: null,
      infowindowContent: null,
      markers: [],
      qqmap_infowin_show: false,
      poi_info: null,
      datapass_block: 0,
      distributor_self: 0, // 總店=1
      dadaEnable: false
    }
  },
  created() {
    const { distributor_type } = this.$route.query
    this.pageQuery = new Pages({
      pageSize: 10,
      fetch: this.getMerchantList
    })
    this.distributor_self = distributor_type === 'distributor_self' ? 1 : 0
    this.getDadaInfo()
    this.getStoreInfo()
  },
  mounted() {
    // this.$nextTick(() => {
    //   this.qqmapinit()
    // })
  },
  methods: {
    async getMerchantList({ page, pageSize }, keywords) {
      let params = {
        pageSize,
        page
      }
      if (!isEmpty(keywords)) {
        params = {
          ...params,
          merchant_name: keywords
        }
      }
      if (page == 1) {
        this.remoteLoading = true
      }
      const { list, total_count } = await this.$api.marketing.getMerchantsList(params)
      if (page == 1) {
        this.remoteLoading = false
      }
      this.pageQuery.setTotal(total_count)
      this.merchantList = this.merchantList.concat(list)
    },
    onRemoteGetMerchant(e) {
      if (!this.form.merchant_id) {
        this.merchantList = []
        this.pageQuery.reset(e)
      }
    },
    searchKeyword() {
      //設置搜尋的範圍和關鍵字等屬性
      const { regions_id, address } = this.form
      if (regions_id.length == 0) {
        this.$message.error('請選擇地區')
        return
      }
      if (!address) {
        this.$message.error('請輸入詳細位置')
        return
      }
      const [province, city, country] = getRegionNameById(regions_id, district)
      this.clearOverlays(this.markers)
      this.searchService.setLocation(
        ['110000', '120000', '310000', '500000'].includes(regions_id[0])
          ? province
          : `${province}${city}`
      ) //設置省市區
      //設置搜尋頁碼
      this.searchService.setPageIndex(0)
      //設置每頁的結果數
      this.searchService.setPageCapacity(5)
      this.searchService.search(address)
    },
    //清除地圖上的marker
    clearOverlays(overlays) {
      let overlay
      while ((overlay = overlays.pop())) {
        overlay.setMap(null)
      }
    },
    // 匯入位置訊息
    importPosition() {
      const {
        latLng: { lng, lat },
        name
      } = this.poi_info
      this.form.lng = lng
      this.form.lat = lat
      this.form.address = name
    },
    async getDadaInfo() {
      const { business_list, is_open } = await this.$api.dada.getDadaInfo()
      const typeList = Object.keys(business_list).reduce((total, current, index) => {
        return total.concat({
          value: Number(current),
          title: business_list[current]
        })
      }, [])
      this.formList.forEach((item) => {
        if (item.key == 'business') {
          item.options = typeList
        }
      })
      this.dadaEnable = is_open === '1'
    },
    async getStoreInfo() {
      const { distributor_id } = this.$route.query
      if (distributor_id || this.IS_DISTRIBUTOR) {
        const res = await this.$api.marketing.getDistributorInfo({ distributor_id })
        const [startTime, endTime] = res.hour.split('-')

        // 退貨點區號、手機號碼
        // 退貨點營業時間段
        let offline_startTime = '',
          offline_endTime = '',
          offline_areaCode = '',
          offline_mobile = ''
        if (isObject(res.offline_aftersales_address)) {
          const { hours, mobile } = res.offline_aftersales_address
          let [t1, t2] = hours.split('-')
          offline_startTime = t1
          offline_endTime = t2
          if (mobile.indexOf('-') > -1) {
            let [code, m] = res.offline_aftersales_address.mobile.split('-')
            offline_areaCode = code
            offline_mobile = m
          } else {
            offline_mobile = mobile
          }
        }
        this.datapass_block = res.datapass_block
        this.form = {
          distribution_type: res.distribution_type,
          merchant_id: res.merchant_id,
          shop_code: res.shop_code,
          name: res.name,
          contact: res.contact,
          mobile: res.mobile,
          contract_phone: res.contract_phone,
          startTime,
          endTime,
          is_delivery: res.is_delivery,
          is_audit_goods: res.is_audit_goods,
          auto_sync_goods: res.auto_sync_goods,
          is_require_subdistrict: res.is_require_subdistrict,
          is_require_building: res.is_require_building,
          logo: res.logo,
          banner: res.banner,
          lng: res.lng,
          lat: res.lat,
          regions_id: res.regions_id,
          address: res.address,
          is_dada: res.is_dada,
          business: res.business,
          is_ziti: res.is_ziti,
          offline_aftersales: res.offline_aftersales === 1,
          offline_aftersales_other: res.offline_aftersales_other === 1,
          offline_aftersales_address: {
            name: res.offline_aftersales_address.name,
            regions_id: res.offline_aftersales_address.regions_id,
            address: res.offline_aftersales_address.address,
            area_code: offline_areaCode,
            mobile: offline_mobile,
            startTime: offline_startTime,
            endTime: offline_endTime
          },
          introduce: res.introduce
        }
        if (res.merchant_name) {
          this.pageQuery.reset(res.merchant_name)
        }
      }
      this.$nextTick(() => {
        // this.qqmapinit()
        this.googleMapInit();
      })
    },
    googleMapInit() {
      const { lat, lng } = this.form
      this.googleMap = new google.maps.Map(document.getElementById("googlemap_container"), {
        center: { lat: parseFloat(lat), lng: parseFloat(lng) },
        zoom: 13,
      });
      this.infowindowContent = document.getElementById("qqmap_infowin");
      this.searchService = new google.maps.places.PlacesService(this.googleMap)
    },
    findPlaceFromQuery() {
      const { regions_id, address } = this.form
      if (regions_id.length == 0) {
        this.$message.error('請選擇地區')
        return
      }
      if (!address) {
        this.$message.error('請輸入詳細位置')
        return
      }
      const [province, city, country] = getRegionNameById(regions_id, district)
      console.log(address);
      const request = {
        query: `${province}${city}${country}${address}`,
        fields: ['name', 'geometry', 'formatted_address'],
        language: 'zh-TW'
      };
      console.log(request.query)
      this.searchService.findPlaceFromQuery(request, (results, status) => {
        console.log(results,status)
        if (status === google.maps.places.PlacesServiceStatus.OK) {
          const infowindow = new google.maps.InfoWindow();
          this.clearOverlays(this.markers)
          console.log(this.markers.toString())
          for (var i = 0; i < results.length; i++) {
            let place = results[i];
            let poi_info = {
              latLng: {
                lng: place.geometry.location.lng(),
                lat: place.geometry.location.lat()
              },
              address: place.formatted_address,
              name: place.name
            }
            const { latLng, name } = poi_info
            if (!place.geometry || !place.geometry.location) return;
            const marker = new google.maps.Marker({
              map: this.googleMap,
            });
            marker.setPosition(latLng)
            this.markers.push(marker)
            google.maps.event.addListener(marker, "click", () => {
              console.log(this.infowindowContent)
              this.qqmap_infowin_show = true
              this.poi_info = poi_info //將選點位置訊息存入poi_info
              infowindow.close();
              infowindow.setContent(this.infowindowContent)
              infowindow.setPosition(latLng)
              infowindow.open(this.googleMap);
            });
          }
          this.googleMap.setCenter(results[0].geometry.location);
        } else {
          this.$message.error('未查詢到數據')
        }
      });
    },
    createMarker(place) {


    },
    qqmapinit() {
      const { lat, lng } = this.form
      // eslint-disable-next-line no-undef
      const center = new qq.maps.LatLng(lat, lng)
      // eslint-disable-next-line no-undef
      const map = new qq.maps.Map(document.getElementById('qqmap_container'), {
        center: center,
        zoom: 13
      })
      // eslint-disable-next-line no-undef
      new qq.maps.Marker({
        position: center,
        map: map
      })
      var that = this
      // eslint-disable-next-line no-undef
      this.searchService = new qq.maps.SearchService({
        panel: document.getElementById('qqmap_rslist'),
        //檢索成功的回調函數
        complete: ({ detail }) => {
          //設置回調函數參數
          const { pois } = detail
          // eslint-disable-next-line no-undef
          const infoWin = new qq.maps.InfoWindow({
            map: map
          })
          if (!pois) {
            return that.$message.error('您輸入的位置有誤')
          }
          // eslint-disable-next-line no-undef
          const latlngBounds = new qq.maps.LatLngBounds()
          for (let i = 0; i < pois.length; i++) {
            let poi = pois[i]
            //擴展邊界範圍，用來包含搜尋到的Poi點
            latlngBounds.extend(poi.latLng)
            // eslint-disable-next-line no-undef
            const marker = new qq.maps.Marker({
              map: map
            })
            marker.setPosition(poi.latLng)
            marker.setTitle(i + 1)
            this.markers.push(marker)
            // eslint-disable-next-line no-undef
            qq.maps.event.addListener(marker, 'click', () => {
              const { latLng, name } = poi
              this.qqmap_infowin_show = true
              this.poi_info = poi //將選點位置訊息存入poi_info
              infoWin.setContent(document.getElementById('qqmap_infowin'))
              infoWin.setPosition(latLng)
              infoWin.open()
              console.log(poi)
            })
          }
          map.fitBounds(latlngBounds)
        },
        error: function () {
          this.$message.error('未查詢到數據')
        }
      })
    },
    handleCancel() {
      this.$router.go(-1)
    },
    async onFormSubmit() {
      try {
        await this.$refs['form'].handleSubmit()
        this.onFormSave()
      } catch (err) {
        console.error(err)
      }
    },
    async onFormSave() {
      this.submitLoading = true
      const { distributor_id, distributor_type } = this.$route.query
      const { offline_aftersales_address } = this.form
      const { regions_id, startTime, endTime } = offline_aftersales_address
      const [province, city, area] = getRegionNameById(regions_id, district)

      const params = {
        ...this.form,
        distributor_self: this.distributor_self,
        regions: getRegionNameById(this.form.regions_id, district),
        hour: `${this.form.startTime}-${this.form.endTime}`,
        offline_aftersales_address: {
          ...offline_aftersales_address,
          regions: [province, city, area],
          hours: `${startTime}-${endTime}`,
          province,
          city,
          area
        },
        offline_aftersales_distributor_id: this.$refs['refundGoodsStore'].finderData.map(
          (item) => item.distributor_id
        )
      }
      if (this.form.distribution_type == 0) {
        delete params.merchant_id
      } else {
        delete params.is_audit_goods
      }
      try {
        if (distributor_id) {
          await this.$api.marketing.updateDistributorInfo(distributor_id, params)
          this.submitLoading = false
          this.$message.success('修改店鋪成功')
        } else {
          const ids = this.$refs['daoDianZiti'].finderData.map((item) => item.id)
          await this.$api.marketing.saveDistributorInfo({
            ...params,
            pickup_location: ids
          })
          this.submitLoading = false
          this.$message.success('儲存店鋪成功')
        }
        if (!this.IS_DISTRIBUTOR) {
          this.$router.go(-1)
        }
      } catch (e) {
        this.submitLoading = false
      }
    }
  }
}
</script>
